export const inferAgroCatalogScenario = (scenario: string): AgroScenarioCatalogItem | null => {
  const normalized = normalizeText(scenario);
  const hasDefensivePricePressure =
    /fungicida|inseticida|fitossanitari|controle de pragas|falhas de controle|retrabalho/.test(normalized) &&
    /desconto|preco|barato|pressionando por desconto|nao pode subir investimento/.test(normalized);
  const hasTimingPressure = /atrasad|timing|janela|aplicacao/.test(normalized);

  if (hasDefensivePricePressure && hasTimingPressure) {
    return AGRO_60_SCENARIOS.find((item) => item.cenarioNome === 'pressiona_preco') ?? null;
  }

  const byName = AGRO_60_SCENARIOS.find((item) => {
    const alias = item.cenarioNome.replace(/_/g, ' ');
    const compact = item.cenarioNome.replace(/_/g, '');
    return normalized.includes(alias) || normalized.includes(compact);
  });

  if (byName) return byName;

  const byDescription = AGRO_60_SCENARIOS.find((item) =>
    normalized.includes(normalizeText(item.descricao))
  );

  if (byDescription) return byDescription;

  const byAliasRule = SCENARIO_ALIAS_RULES.find((item) => item.regex.test(normalized));
  if (!byAliasRule) return null;

  return AGRO_60_SCENARIOS.find((item) => item.cenarioNome === byAliasRule.cenarioNome) ?? null;
};
